// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *CatalogMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockGetTargetInspect()

			m.MinimockHasLOD0Inspect()

			m.MinimockListTargetsInspect()

			m.MinimockRegisterArtifactInspect()

			m.MinimockRescaleTerritoryPlacementsInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *CatalogMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *CatalogMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockGetTargetDone() &&
		m.MinimockHasLOD0Done() &&
		m.MinimockListTargetsDone() &&
		m.MinimockRegisterArtifactDone() &&
		m.MinimockRescaleTerritoryPlacementsDone()
}
